SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_dep_m_creditor_item ON sc_dep_m_creditor_item CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_dep_m_creditor_item() RETURNS trigger AS $BODY$
BEGIN
  if (pka.auto_seqno) then
    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
      select max(seq_no) into STRICT NEW.seq_no
      from sc_dep_m_creditor_item
      where (deposit_account_no = NEW.deposit_account_no);
      NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
    end if;
  end if;

  if coalesce(NEW.deposit_balance::text, '') = '' then NEW.deposit_balance := 0;end if;
  if coalesce(NEW.deposit_real,0) = 0 then NEW.deposit_real := NEW.deposit_balance;end if;
  if coalesce(NEW.dep_ret_to_int,0) = 0 then NEW.dep_ret_to_int := NEW.deposit_balance;end if;

  if coalesce(NEW.total_balance::text, '') = '' then NEW.total_balance :=0;end if;
  if coalesce(NEW.total_real::text, '') = '' then NEW.total_real := NEW.total_balance;end if;

  if coalesce(trim(both NEW.refer_to_deposit_doc_no)::text, '') = '' then NEW.refer_to_deposit_doc_no := 'NB';end if;
  if coalesce(NEW.old_acc_int::text, '') = '' then NEW.old_acc_int :=0;end if;
  if coalesce(NEW.interest_rate::text, '') = '' then NEW.interest_rate :=0;end if;
  if coalesce(NEW.refer_seq_no::text, '') = '' then NEW.refer_seq_no :=0;end if;
  if coalesce(NEW.fee_amount::text, '') = '' then NEW.fee_amount :=0;end if;
  if coalesce(NEW.int_amount::text, '') = '' then NEW.int_amount :=0;end if;
  if coalesce(NEW.tax_amount::text, '') = '' then NEW.tax_amount :=0;end if;
  if coalesce(NEW.ret_int::text, '') = '' then NEW.ret_int :=0;end if;
  if coalesce(NEW.working_day::text, '') = '' then NEW.working_day := pka_dep.fp_deposit_date();end if;
  if coalesce(NEW.paidintnostm::text, '') = '' then NEW.paidintnostm :=0;end if;
  if coalesce(NEW.accu_int_item::text, '') = '' then NEW.accu_int_item :=0;end if;
  if coalesce(NEW.conclude_book::text, '') = '' then NEW.conclude_book :=0;end if;
  if coalesce(NEW.ref_int_rate::text, '') = '' then NEW.ref_int_rate :=0;end if;
  if coalesce(NEW.calpaidintdate::text, '') = '' then NEW.calpaidintdate := NEW.operate_date;end if;
  if coalesce(NEW.start_int_cheque_date::text, '') = '' then NEW.start_int_cheque_date := NEW.operate_date;end if;-- ให้ใช้เป็นวันที่เดียวกันกับวันที่ฝากเสมอ
  if coalesce(trim(both NEW.cheque_clearing_status)::text, '') = '' then NEW.cheque_clearing_status := '2';end if;

--NIGHT 2020/03/20 KTM >> เปลี่ยนจาก print_status 2 เป็น 0 แทน
--if trim(:new.print_status) is null then :new.print_status :='2';end if;
  if coalesce(trim(both NEW.print_status)::text, '') = '' then NEW.print_status :='0';end if;
  if coalesce(trim(both NEW.cancle_status)::text, '') = ''  then NEW.cancle_status :='0';end if;
  if coalesce(NEW.ref_seq_no_adj::text, '') = '' then NEW.ref_seq_no_adj :=0;end if;
  if coalesce(trim(both NEW.card_status)::text, '') = '' then NEW.card_status :='2';end if;

--NIGHT 2020/03/20 KTM >> เปลี่ยนจาก print_status 2 เป็น 0 แทน
--if trim(:new.book_status) is null then :new.book_status :='2';end if;
  if coalesce(trim(both NEW.book_status)::text, '') = '' then NEW.book_status :='0';end if;
  if coalesce(NEW.auto_print_status::text, '') = '' then NEW.auto_print_status :='0';end if;

  if coalesce(NEW.last_access_date::text, '') = '' then NEW.last_access_date  := statement_timestamp();end if;
  if coalesce(trim(both NEW.officer_id)::text, '') = '' then NEW.officer_id := current_setting('app.login_id', true);end if;
  if coalesce(trim(both NEW.branch_id)::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;
  if coalesce(trim(both NEW.client_id)::text, '') = '' then NEW.client_id := pka_com_login.login_pc;end if;
  if coalesce(NEW.withdrawable_amount::text, '') = '' then NEW.withdrawable_amount :=0;end if;
  if coalesce(NEW.cheque_pending_amount::text, '') = '' then NEW.cheque_pending_amount :=0;end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_dep_m_creditor_item() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_dep_m_creditor_item
	BEFORE INSERT OR UPDATE ON sc_dep_m_creditor_item FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_dep_m_creditor_item();

